arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// --- Train the model at startup and register it for pooled prediction ---
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var allData = mlContext.Data.LoadFromTextFile<CustomerInput>(dataPath, hasHeader: true, separatorChar: ',');
var split = mlContext.Data.TrainTestSplit(allData, testFraction: 0.2, seed: 42);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerInput.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerInput.Age),
        nameof(CustomerInput.Income),
        nameof(CustomerInput.PurchaseHistory),
        "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label",
        featureColumnName: "Features"));

// Map "Yes"/"No" to boolean label before training
var labelPipeline = mlContext.Transforms.CustomMapping<CustomerInput, LabeledCustomer>(
    (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
    contractName: "ChurnLabel");

var fullPipeline = labelPipeline.Append(pipeline);
var model = fullPipeline.Fit(split.TrainSet);

// Evaluate on test set
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

// Save model and register prediction engine pool
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");
mlContext.Model.Save(model, allData.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => new
{
    endpoints = new[] { "POST /predict", "GET /metrics" },
    sampleBody = new { Age = 40f, Income = 70000f, Region = "West", PurchaseHistory = 5f }
});

app.MapPost("/predict", (CustomerRequest req, PredictionEnginePool<CustomerInput, ChurnPrediction> pool) =>
{
    var input = new CustomerInput
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory,
        Churned = "" // not needed for prediction
    };

    var result = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = result.PredictedLabel,
        Probability = result.Probability,
        Score = result.Score
    });
});

// Expose the evaluation metrics
app.MapGet("/metrics", () => new
{
    metrics.Accuracy,
    metrics.AreaUnderRocCurve,
    metrics.F1Score,
    metrics.PositivePrecision,
    metrics.PositiveRecall
});

app.Run();

// --- Data models ---

public class CustomerInput
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] public string Churned { get; set; } = "";
}

public class LabeledCustomer
{
    public bool Label { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")] public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}

public record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

